import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
} from 'chart.js';
import { Line } from 'react-chartjs-2';
import '../styles/GraphsOfChanges.css';

// Реєструємо компоненти Chart.js
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

function GraphsOfChanges() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [healthData, setHealthData] = useState([]);
  const [selectedIndicators, setSelectedIndicators] = useState([]);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);

  const indicators = [
    { id: 'FEV1', label: 'FEV1', color: 'rgb(255, 99, 132)' },
    { id: 'FVC', label: 'FVC', color: 'rgb(54, 162, 235)' },
    { id: 'PEF', label: 'PEF', color: 'rgb(75, 192, 192)' },
    { id: 'respiratory_rate', label: 'Respiratory Rate', color: 'rgb(255, 206, 86)' },
    { id: 'pulse', label: 'Pulse', color: 'rgb(153, 102, 255)' },
    { id: 'cough', label: 'Cough', color: 'rgb(255, 159, 64)' },
    { id: 'breathlessness', label: 'Breathlessness', color: 'rgb(199, 199, 199)' },
    { id: 'wheezing', label: 'Wheezing', color: 'rgb(83, 102, 255)' },
    { id: 'chest_tightness', label: 'Chest Tightness', color: 'rgb(255, 99, 255)' },
    { id: 'nighttime_awakenings', label: 'Nighttime Awakenings', color: 'rgb(99, 255, 132)' }
  ];

  useEffect(() => {
    fetchHealthData();
  }, []);

  const fetchHealthData = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch(`http://localhost:5000/api/health_records/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch health data');
      }
      const data = await response.json();
      setHealthData(data.sort((a, b) => new Date(a.date) - new Date(b.date)));
    } catch (err) {
      console.error('Error fetching health data:', err);
      setError('Failed to load health data');
    }
  };

  const handleIndicatorChange = (indicatorId) => {
    setSelectedIndicators(prev => {
      if (prev.includes(indicatorId)) {
        return prev.filter(id => id !== indicatorId);
      } else {
        return [...prev, indicatorId];
      }
    });
  };

  const generateGraph = () => {
    if (selectedIndicators.length === 0) {
      setError('Please select at least one indicator');
      return;
    }
    setError(null);
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  const getChartData = () => {
    if (!healthData.length || selectedIndicators.length === 0) return null;

    const dates = healthData.map(record => new Date(record.date).toLocaleDateString());
    
    const datasets = selectedIndicators.map(indicator => {
      const indicatorInfo = indicators.find(i => i.id === indicator);
      return {
        label: indicatorInfo.label,
        data: healthData.map(record => record[indicator] || null),
        borderColor: indicatorInfo.color,
        backgroundColor: indicatorInfo.color,
        tension: 0.1,
        pointRadius: 5,
        pointHoverRadius: 7
      };
    });

    return {
      labels: dates,
      datasets
    };
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Health Indicators Over Time'
      },
      tooltip: {
        mode: 'index',
        intersect: false,
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        title: {
          display: true,
          text: 'Value'
        }
      },
      x: {
        title: {
          display: true,
          text: 'Date'
        }
      }
    },
    interaction: {
      mode: 'nearest',
      axis: 'x',
      intersect: false
    }
  };

  return (
    <div className={`graphs-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={() => navigate('/profile')} className="profile-button">
            Profile
          </button>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className="content">
        <h2>Graphs of Changes</h2>
        
        <div className="indicators-selection">
          <h3>Select Indicators to Display</h3>
          <div className="indicators-grid">
            {indicators.map(indicator => (
              <label key={indicator.id} className="indicator-checkbox">
                <input
                  type="checkbox"
                  checked={selectedIndicators.includes(indicator.id)}
                  onChange={() => handleIndicatorChange(indicator.id)}
                />
                <span>{indicator.label}</span>
              </label>
            ))}
          </div>
          <button
            className="generate-graph-button"
            onClick={generateGraph}
            disabled={selectedIndicators.length === 0}
          >
            Generate Graph
          </button>
        </div>

        {error && <div className="error-message">{error}</div>}
        
        <div className="graph-container">
          {getChartData() ? (
            <Line data={getChartData()} options={chartOptions} />
          ) : (
            <div className="no-indicators">
              {selectedIndicators.length === 0 
                ? 'Please select indicators to display the graph'
                : 'No data available for the selected indicators'}
            </div>
          )}
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default GraphsOfChanges;
